// ImplementationOS — step definitions.
//
// Each step is one decision. `gate` returns whether Continue unlocks; `body`
// renders the screen; `attach` wires its controls (and calls the global
// `render` from app.js after mutating state). The attribute family steps are
// generated by `makeAttributeStep`. Depends on data.js, state.js, derive.js,
// util.js, and (at runtime) model.js's `Model` plus app.js's `render`.

// ── Capacity Gantt ───────────────────────────────────────────────────
// A day-scale (00–24 h) timeline for resources R1–R4. Each row's track is
// hatched to mean "capacity blocked"; solid teal blocks are working shifts,
// and amber `.exception` blocks are holidays or maintenance carved out of a
// shift. Used by the two calendar visualization steps — one fixed teaching
// example, one derived from the user's own calendar choices.
const ganttTicks = [0, 4, 8, 12, 16, 20, 24];
function ganttHourPct(hour) { return (hour / 24) * 100; }
function ganttMarkup(rows) {
  const ticks = ganttTicks.map((h) => `<span style="left:${ganttHourPct(h)}%">${String(h).padStart(2, "0")}</span>`).join("");
  const body = rows.map((row) => {
    const blocks = (row.blocks || []).map((b) => {
      const left = ganttHourPct(b.start);
      const width = ganttHourPct(b.end) - left;
      return `<span class="gantt-block ${b.type || "shift"}" style="left:${left}%;width:${width}%"><em>${escapeHtml(b.label || "")}</em></span>`;
    }).join("");
    return `<div class="gantt-row"><span class="gantt-label">${escapeHtml(row.label)}${row.badge ? `<b>${escapeHtml(row.badge)}</b>` : ""}</span><div class="gantt-track">${blocks}</div></div>`;
  }).join("");
  return `
    <div class="gantt" role="img" aria-label="Resource capacity across a 24 hour day">
      <div class="gantt-row gantt-axis"><span class="gantt-label"></span><div class="gantt-ticks">${ticks}</div></div>
      ${body}
    </div>
    <div class="gantt-legend">
      <span><i class="gantt-swatch shift"></i>Working shift — available capacity</span>
      <span><i class="gantt-swatch blocked"></i>Off-shift — capacity blocked</span>
      <span><i class="gantt-swatch exception"></i>Holiday / maintenance exception</span>
    </div>`;
}

// Fixed teaching example: four resources, four ways a calendar shapes capacity.
const ganttIntroRows = [
  { label: "R1", badge: "1 shift", blocks: [{ start: 6, end: 14, label: "Day" }] },
  { label: "R2", badge: "2 shifts", blocks: [{ start: 6, end: 14, label: "Day" }, { start: 14, end: 22, label: "Late" }] },
  { label: "R3", badge: "continuous", blocks: [{ start: 0, end: 24, label: "24 h" }] },
  { label: "R4", badge: "+ maint.", blocks: [{ start: 6, end: 10, label: "Day" }, { start: 10, end: 11, type: "exception", label: "PM" }, { start: 11, end: 14, label: "Day" }] },
];

// Clip any shift overlapping [a,b] and drop an exception block into the gap.
function ganttInjectException(blocks, a, b, label) {
  const out = [];
  blocks.forEach((bl) => {
    if (b <= bl.start || a >= bl.end) { out.push(bl); return; }
    if (a > bl.start) out.push({ ...bl, end: a });
    if (b < bl.end) out.push({ ...bl, start: b });
  });
  out.push({ start: a, end: b, type: "exception", label });
  return out.sort((x, y) => x.start - y.start);
}

// Translate the four calendar choices into preview rows for R1–R4.
function calendarPreviewRows() {
  const cal = state.calendar || {};
  const labels = ["R1", "R2", "R3", "R4"];
  let rows;
  if (cal.pattern === "multi-shift") {
    rows = labels.map((r) => ({ label: r, blocks: [{ start: 6, end: 14, label: "Day" }, { start: 14, end: 22, label: "Late" }] }));
  } else if (cal.pattern === "variable") {
    rows = [
      { label: "R1", blocks: [{ start: 6, end: 14, label: "Day" }] },
      { label: "R2", blocks: [{ start: 14, end: 22, label: "Late" }] },
      { label: "R3", blocks: [{ start: 0, end: 24, label: "24 h" }] },
      { label: "R4", blocks: [{ start: 0, end: 6, label: "Night" }, { start: 22, end: 24, label: "Night" }] },
    ];
  } else { // single-shift (default)
    rows = labels.map((r) => ({ label: r, blocks: [{ start: 6, end: 14, label: "Day" }] }));
  }
  if (cal.exceptions === "resource-overrides") {
    const r3 = rows.find((x) => x.label === "R3") || rows[2];
    if (r3) r3.blocks = ganttInjectException(r3.blocks, 12, 13, "PM");
  } else if (cal.exceptions === "multi-activity") {
    const acts = ["Production", "Packaging", "Quality", "Logistics"];
    rows.forEach((row, i) => { row.badge = acts[i]; });
  }
  if ((cal.modifiers || []).includes("units")) {
    const parallel = [3, 2, 1, 2];
    rows.forEach((row, i) => { row.badge = `${row.badge ? row.badge + " · " : ""}×${parallel[i] || 1}`; });
  }
  return rows;
}

function calendarPreviewCaption() {
  const cal = state.calendar || {};
  const pattern = { "single-shift": "Single shift", "multi-shift": "Multiple shifts", "variable": "Variable / rotating" }[cal.pattern] || "Shifts";
  const exc = { "base-only": "site-wide holidays", "resource-overrides": "resource overrides", "multi-activity": "activity-specific availability" }[cal.exceptions] || "exceptions";
  const mods = [];
  if ((cal.modifiers || []).includes("units")) mods.push("parallel units");
  if ((cal.modifiers || []).includes("efficiency")) mods.push("efficiency factor");
  if ((cal.modifiers || []).includes("category")) mods.push("capacity categories");
  return `${pattern} · ${exc}${mods.length ? " · " + mods.join(" · ") : ""}`;
}

// ── Bottleneck / CCR load Gantt ──────────────────────────────────────
// Same R1–R4 timeline, but blocks are committed jobs and the track shows
// idle slack instead of blocked time. The capacity-constrained resource
// (CCR) runs closest to full; a row marked `ccr` (or individual `ccr`
// blocks, for a shifting bottleneck) is highlighted amber.
function loadGanttMarkup(rows, opts = {}) {
  const ticks = ganttTicks.map((h) => `<span style="left:${ganttHourPct(h)}%">${String(h).padStart(2, "0")}</span>`).join("");
  const divider = opts.divider != null ? `<span class="gantt-divider" style="left:${ganttHourPct(opts.divider)}%"></span>` : "";
  const body = rows.map((row) => {
    const blocks = (row.blocks || []).map((b) => {
      const left = ganttHourPct(b.start);
      const width = ganttHourPct(b.end) - left;
      return `<span class="gantt-block job${b.ccr ? " ccr" : ""}" style="left:${left}%;width:${width}%"></span>`;
    }).join("");
    return `<div class="gantt-row${row.ccr ? " ccr" : ""}"><span class="gantt-label">${escapeHtml(row.label)}${row.badge ? `<b>${escapeHtml(row.badge)}</b>` : ""}</span><div class="gantt-track">${divider}${blocks}</div></div>`;
  }).join("");
  return `
    <div class="gantt gantt-load" role="img" aria-label="Resource load timeline highlighting the bottleneck">
      <div class="gantt-row gantt-axis"><span class="gantt-label"></span><div class="gantt-ticks">${ticks}</div></div>
      ${body}
    </div>
    <div class="gantt-legend">
      <span><i class="gantt-swatch job"></i>Committed work</span>
      <span><i class="gantt-swatch idle"></i>Idle — slack capacity</span>
      <span><i class="gantt-swatch ccr"></i>Bottleneck — capacity-constrained resource</span>
    </div>`;
}

